import React from 'react';

export default function Footer() {
  return (
    <footer>
      <p>Designed &amp; Built with <span>♥</span> by <span>Soham Das Biswas</span> &nbsp;·&nbsp; DevOps Engineer &amp; Cloud Architect</p>
      <p style={{ marginTop: '0.4rem' }}>© {new Date().getFullYear()} All rights reserved.</p>
    </footer>
  );
}
